@@ -3874,9 +3874,15 @@ impl TensorTape {
         input: TensorNodeId,
     ) -> Result<TensorNodeId, AutogradError> {
         let input_node = self.node(input)?;
-        if input_node.tensor.meta().dtype() == DType::F32 {
+        let input_dtype = input_node.tensor.meta().dtype();
